private Set<String> keys(Object obj) {
  Set<String> set = new HashSet<>();
  try {
    Field[] fields = obj.getClass().getDeclaredFields();
    for (Field field : fields) {
      String name = field.getName();
      set.add(name);
    }
  } catch (Exception e) {
    System.err.println("error:" + e.getMessage());
  }
  return set;
}

